  // To isolate base premium tests, we use a long-standing customer's follow-up contract? Actually simpler: use 0 years + first contract = first insurance surcharge applies.
  // Let's add tests for each item type as single-item quotes with surcharges applied.
  it("single sword (steel, enchantment 3, not cursed), newcomer, first contract → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    };
    const output = runScenario(input);
    expect(output).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (silver, enchantment 2, not cursed), newcomer, first contract → 60 + 6 + 5 = 71 G", () => {
    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    };
    const output = runScenario(input);
    expect(output).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("single staff (wood, enchantment 1, not cursed), newcomer, first contract → 80 + 8 + 5 = 93 G");
  it.todo("single potion (glass, not cursed), newcomer, first contract → 40 + 4 + 5 = 49 G");

  // --- Components (runes, moonstones) ---
  it.todo("1 rune, newcomer, first contract → 25 + 2.5 + 5 = 33 G (rounded up)");
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (no block — 7 not multiple of 3 nor exactly 3)");

  // --- Alike components clarification (❓) ---
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Cursed surcharge ---
  it.todo("cursed sword (steel, enchantment 3), newcomer, first contract → 100 + 50 curse + 10 first = 160 + 5 fee = 165 G");

  // --- High enchantment surcharge ---
  it.todo("sword enchantment 5 (not cursed), newcomer, first contract → 100 + 30 + 10 = 140 + 5 = 145 G (enchantment exactly 5 triggers surcharge)");
  it.todo("sword enchantment 4 (not cursed), newcomer, first contract → 100 + 10 = 110 + 5 = 115 G (no high-enchantment surcharge)");
  it.todo("cursed sword enchantment 5, newcomer, first contract → 100 + 50 + 30 + 10 = 190 + 5 = 195 G (both surcharges apply)");

  // --- Loyalty discount threshold ---
  it.todo("customer with exactly 2 years, single sword, first contract → 100 - 20 loyalty + 10 first = 90 + 5 = 95 G");

  // --- Modifier scope on multi-item policies ---
  it.todo("policy with cursed sword + plain amulet, newcomer, first contract → 100 + 60 + 50 curse + 16 first = 226 + 5 = 231 G");

  // --- Rounding in MHPCO favor (premium rounds up) ---
  it.todo("premium calculation yielding 197.5 → final premium 198 G (rounded up)");

  // --- Integration example: newcomer with cursed sword ---
  it.todo("newcomer (0 years), cursed sword (steel, enchantment 3), first contract → 165 G");

  // --- Integration example: long-standing customer's second contract ---
  it.todo("3-year customer's second quote: cursed sword enchantment 7 → 160 G");

  // --- First-insurance applies per item, even on follow-up contract (❓) ---
  it.todo("follow-up contract still gets first-insurance surcharge per item (clarification from integration example)");

  // --- Claims: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 (500 - 100 deductible)");
  it.todo("rune damage 200 → payout 100 (no special clause; 200 - 100 deductible)");

  // --- Claims: dragon material ---
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full reimbursement minus deductible)");

  // --- Claims: high enchantment (≥8) ---
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");

  // --- Claims: dragon material AND enchantment ≥ 8 (50% wins) ---
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");

  // --- Claims: deductible per damage event (per item) ---
  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible applies per item: 400 + 200)");

  // --- Claims: cap = 2x insurance sum ---
  it.todo("policy covering sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000) → cap 2000 G (cap based on unmodified value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount doesn't affect sum)");

  // --- Cap exhaustion across multiple claims ---
  it.todo("sword (cap 2000), claim 1 of 1500 → payout 1400, remainingCap 600");
  it.todo("sword (cap 2000), claim 1 of 1500 then claim 2 of 1500 → payout 1400 then 600, remainingCap 600 then 0");

  // --- Rounding payout down (MHPCO favor) ---
  it.todo("payout calculation yielding 350.5 → final payout 350 G (rounded down)");

  // --- Multiple items of same type (❓) ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("dragon attack damages both swords (two damage entries) → each gets its own deductible");

  // --- Error cases ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr");
  it.todo("claim references damage item not part of policy → CLI exits non-zero");
  it.todo("damages contains more entries of a type than policy covers → claim rejected, CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
});

