    const input = {
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    };
    const output = runScenario(input);
    expect(output).toEqual({ results: [{ premium: 60 }] });
  });
