const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const ALIKE_BLOCK_SIZE = 3;
const ALIKE_BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type Step = { items: Item[] };
type Scenario = { steps: Step[] };

const isBlockOfAlikeComponents = (items: Item[]): boolean =>
  items.length === ALIKE_BLOCK_SIZE &&
  items.every((it) => it.type === items[0].type);

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((acc, { type }) => acc + BASE_PREMIUM[type], 0);

const basePremiumForItems = (items: Item[]): number =>
  isBlockOfAlikeComponents(items) ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(items);

const quotePremium = (items: Item[]): number => {
  const basePremium = basePremiumForItems(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(basePremium + firstInsuranceSurcharge) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

