62	  items.reduce((acc, item) => acc + basePremiumOf(item), 0);
63	
64	const basePremiumForGroup = (group: Item[]): number =>
65	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
66	
67	const basePremiumForItems = (items: Item[]): number =>
68	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
69	
70	const cursedSurcharge = (item: Item): number =>
71	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
72	
73	const highEnchantmentSurcharge = (item: Item): number =>
74	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
75	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
76	    : 0;
77	
78	const itemSurcharges = (items: Item[]): number =>
79	  items.reduce(
80	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
81	    0,
82	  );
83	
84	const firstInsuranceSurcharge = (basePremium: number): number =>
85	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
86	
87	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
88	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
89	
90	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
91	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
92	
93	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
94	  const basePremium = basePremiumForItems(items);
95	  return (
96	    Math.ceil(
97	      basePremium +
98	        itemSurcharges(items) +
99	        firstInsuranceSurcharge(basePremium) -
100	        loyaltyDiscount(basePremium, customer) -
101	        followUpDiscount(basePremium, isFollowUp),
102	    ) + PROCESSING_FEE
103	  );
104	};
105	
106	const insuranceSum = (items: Item[]): number =>
107	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
108	
109	const reimbursableAmount = (item: Item, damageAmount: number): number =>
110	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
111	    ? damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE
112	    : damageAmount;
113	
114	const payoutForDamage = (item: Item, damage: Damage): number =>
115	  reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
116	
117	const openPolicy = (items: Item[]): Policy => ({
118	  items,
119	  cap: insuranceSum(items) * CAP_MULTIPLIER,
120	});
121	
122	const findItem = (policy: Policy, itemType: string): Item =>
123	  policy.items.find((i) => i.type === itemType) as Item;
124	
125	const countDamagesByType = (damages: Damage[]): Map<string, number> => {
126	  const counts = new Map<string, number>();
127	  for (const damage of damages) {
128	    counts.set(damage.itemType, (counts.get(damage.itemType) ?? 0) + 1);
129	  }
130	  return counts;
131	};
132	
133	const policyItemCount = (policy: Policy, itemType: string): number =>
134	  policy.items.filter((item) => item.type === itemType).length;
135	
136	const assertDamagesCoveredByPolicy = (policy: Policy, damages: Damage[]): void => {
137	  for (const [itemType, count] of countDamagesByType(damages)) {
138	    if (count > policyItemCount(policy, itemType)) {
139	      throw new Error(`Damage references item not in policy: ${itemType}`);
140	    }
141	  }
142	};
143	
144	const assertNonNegativeDamageAmounts = (damages: Damage[]): void => {
145	  for (const damage of damages) {
146	    if (damage.amount < 0) {
147	      throw new Error(`Negative damage amount: ${damage.amount}`);
148	    }
149	  }
150	};
151	
152	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
153	  const payoutFor = (damage: Damage) => payoutForDamage(findItem(policy, damage.itemType), damage);
154	  const desiredPayout = incident.damages.reduce((sum, damage) => sum + payoutFor(damage), 0);
155	  const payout = Math.floor(Math.min(desiredPayout, policy.cap));
156	  return { payout, remainingCap: policy.cap - payout };
157	};
158	
159	export const runScenario = (scenario: Scenario): unknown => {
160	  const policies: Policy[] = [];
161	
162	  const handleQuote = (step: QuoteStep) => {
163	    assertKnownItemTypes(step.items);
164	    const isFollowUp = policies.length > 0;
165	    policies.push(openPolicy(step.items));
166	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
167	  };
168	
169	  const handleClaim = (step: ClaimStep) => {
170	    const policy = policies[step.policy];
171	    assertNonNegativeDamageAmounts(step.incident.damages);
172	    assertDamagesCoveredByPolicy(policy, step.incident.damages);
173	    const result = settleClaim(policy, step.incident);
174	    policies[step.policy] = { ...policy, cap: result.remainingCap };
175	    return result;
176	  };
177	
178	  const results = scenario.steps.map((step) =>
179	    step.op === "claim" ? handleClaim(step) : handleQuote(step),
180	  );
181	  return { results };
182	};

